tion:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.2),transparent);transition:left 0.5s}\n.elec-cta-btn:hover::before{left:100%}\n.elec-cta-btn--primary{background:#fff;color:#003CC8;font-weight:600;box-shadow:0 4px 20px rgba(0,0,0,0.15)}\n.elec-cta-btn--primary:hover{transform:translateY(-3px);box-shadow:0 12px 40px rgba(0,0,0,0.2)}\n.elec-cta-btn--ghost{background:transparent;color:#fff;border:2px solid rgba(255,255,255,0.6)}\n.elec-cta-btn--ghost:hover{background:rgba(255,255,255,0.15);border-color:#fff}\n.elec-cta-btn-row{display:flex;gap:20px;flex-wrap:wrap;justify-content:center;position:relative;z-index:2}\n.elec-cta-btn{position:static;overflow:visible;display:inline-flex;align-items:center;gap:8px;padding:16px 32px;border-radius:8px;line-height:1.6}\n@media(max-width:767px){\n  .elec-cta-title{font-size:28px;margin-bottom:16px}\n  .elec-cta-subtitle{font-size:16px;margin-bottom:32px}\n  .elec-cta-btn-row{flex-direction:column;align-items:stretch;gap:16px}\n  .elec-cta-btn{width:100%;max-width:300px;margin:0 auto;text-align:center}\n}\n@media(prefers-reduced-motion:reduce){.elec-cta-btn{transition:none !important}.elec-cta-btn::before{display:none}}\n\n.et_pb_section:has(.elec-related-section){background:#F5F7FA;padding:0}\n.elec-related-section{padding:60px 5%;background:#F5F7FA;max-width:100%;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto}\n.elec-related-heading{font-family:\'Noto Sans\',sans-serif;font-size:28px;font-weight:600;color:#000864;margin:0 0 32px 0;padding:0;text-align:center;line-height:1.6;-webkit-font-smoothing:auto}\n.elec-related-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:24px;max-width:1200px;margin:0 auto}\n.elec-related-card{display:block;padding:24px;background:#fff;border-radius:12px;text-decoration:none;border:1px solid #e5e7eb;transition:box-shadow 0.3s ease;color:#333;line-height:1.6}\n.elec-related-card:hover{box-shadow:0 8px 24px rgba(0,8,100,0.1)}\n.elec-related-card-title{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;margin:0 0 8px 0;padding:0;line-height:1.6;-webkit-font-smoothing:auto}\n.elec-related-card-desc{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#666;margin:0;padding:0;line-height:1.5;-webkit-font-smoothing:auto}\n@media(prefers-reduced-motion:reduce){.elec-related-card{transition:none}}\n\n/* === THAI TYPOGRAPHY === */\n/* Font loaded via <link> in header — do NOT use @import here (invalid after rules) */\n\n/* Thai font stack for all body text */\nbody, .et_pb_section, .et_pb_code, .et_pb_code_inner {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* Thai-specific line heights (Thai script is taller — needs !important to override Divi) */\np, li, .et_pb_text_inner { line-height: 1.8 !important; }\nh1, h2, h3, h4, h5, h6 { line-height: 1.4 !important; }\n\n/* Thai label override: JetBrains Mono doesn\'t have Thai glyphs.\n   letter-spacing breaks Thai script (chars within words must stay connected).\n   text-transform:uppercase is meaningless for Thai. */\n[class*="-label"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n/* Also fix any monospace elements that might contain Thai text */\n[class*="-source"], [class*="-company"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: Electronics (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: Electronics (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Hero: Electronics (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="elec-hero">\n    <div class="dw-d-bg dw-d-bg--top" style="opacity: 0.12;"></div>\n            <div class="elec-hero-inner" style="position: relative; z-index: 2;">\n                <div class="elec-hero-badge">\n                    <span>Electronics Assembly</span>\n                </div>\n                <h1>ความแม่นยำสำหรับการผลิต <span>High-Mix</span></h1>\n                <p class="elec-hero-subtitle">ชิ้นส่วนนับพันต่อบอร์ด วงจรผลิตภัณฑ์ที่เปลี่ยนเร็ว Traceability ครบทุกจุด ออกแบบมาเฉพาะสำหรับความซับซ้อนของอิเล็กทรอนิกส์</p>\n                <div class="elec-hero-stats">\n                    <div class="elec-hero-stat">\n                        <div class="elec-hero-stat-value">1000+</div>\n                        <div class="elec-hero-stat-label">ประเภทชิ้นส่วนที่ติดตาม</div>\n                    </div>\n                    <div class="elec-hero-stat">\n                        <div class="elec-hero-stat-value">99.9%</div>\n                        <div class="elec-hero-stat-label">ความแม่นยำในการหยิบ</div>\n                    </div>\n                    <div class="elec-hero-stat">\n                        <div class="elec-hero-stat-value">-45%</div>\n                        <div class="elec-hero-stat-label">ลดของเสียจาก MSD</div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Context: ระบบนิเวศอิเล็กทรอนิกส์ไทย (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Context: ระบบนิเวศอิเล็กทรอนิกส์ไทย (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Context: ระบบนิเวศอิเล็กทรอนิกส์ไทย (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="context-section">\n    <div class="context-inner">\n                <h2>ระบบนิเวศอิเล็กทรอนิกส์ของประเทศไทย</h2>\n                <p>ประเทศไทยส่งออก<strong>อิเล็กทรอนิกส์มูลค่ากว่า 40,000 ล้านดอลลาร์สหรัฐต่อปี</strong> ตั้งแต่ฮาร์ดดิสก์ไดรฟ์ไปจนถึงอิเล็กทรอนิกส์ยานยนต์และอุปกรณ์อิเล็กทรอนิกส์สำหรับผู้บริโภค ผู้ผลิตอิเล็กทรอนิกส์เผชิญกับความซับซ้อนเฉพาะตัว: <strong>ชิ้นส่วนหลายร้อยรายการต่อผลิตภัณฑ์</strong> การเปลี่ยนงานบ่อยครั้งสำหรับการผลิตแบบ High-Mix และชิ้นส่วนที่ไวต่อความชื้นซึ่งต้องการการจัดการอย่างแม่นยำ DigiWin MES ถูกสร้างมาเฉพาะสำหรับความท้าทายนี้</p>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Challenges: ความท้าทายในการผลิตอิเล็กทรอนิกส์ (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Challenges: ความท้าทายในการผลิตอิเล็กทรอนิกส์ (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Challenges: ความท้าทายในการผลิตอิเล็กทรอนิกส์ (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="challenges-section">\n    <div class="dw-wave-vertical--right" style="opacity: 0.06;"></div>\n            <div class="challenges-inner" style="position: relative; z-index: 2;">\n                <div class="challenges-header">\n                    <h2>ความท้าทายในการผลิตอิเล็กทรอนิกส์</h2>\n                    <p>ความซับซ้อนที่ระบบทั่วไปจัดการไม่ได้</p>\n                </div>\n                <div class="challenges-grid">\n                    <div class="challenge-card">\n                        <div class="challenge-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1 0 2.83 2 2 0 0 1-2.83 0l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-2 2 2 2 0 0 1-2-2v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83 0 2 2 0 0 1 0-2.83l.06-.06a1.65 1.65 0 0 0 .33-1.82 1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1-2-2 2 2 0 0 1 2-2h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 0-2.83 2 2 0 0 1 2.83 0l.06.06a1.65 1.65 0 0 0 1.82.33H9a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 2-2 2 2 0 0 1 2 2v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 0 2 2 0 0 1 0 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82V9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 2 2 2 2 0 0 1-2 2h-.09a1.65 1.65 0 0 0-1.51 1z"/></svg></div>\n                        <h3>ชิ้นส่วนวุ่นวาย</h3>\n                        <p>ชิ้นส่วนหลายร้อยรายการต่อผลิตภัณฑ์ รีลนับพันในคลังสินค้า วางชิ้นส่วนผิดเพียงตัวเดียว = ทิ้งทั้งล็อต</p>\n                    </div>\n                    <div class="challenge-card">\n                        <div class="challenge-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg></div>\n                        <h3>เปลี่ยนงานบ่อย</h3>\n                        <p>การผลิตแบบ High-Mix, Low-Volume หมายถึงการเปลี่ยนงานตลอดเวลา ทุกนาทีของเวลาตั้งเครื่องคือกำลังการผลิตที่สูญเสียไป</p>\n                    </div>\n                    <div class="challenge-card">\n                        <div class="challenge-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2v6l3-3"/><path d="M12 8l-3-3"/><path d="M12 22v-6l3 3"/><path d="M12 16l-3 3"/><path d="M2 12h6l-3 3"/><path d="M8 12l-3-3"/><path d="M22 12h-6l3 3"/><path d="M16 12l3-3"/></svg></div>\n                        <h3>ชิ้นส่วนไวต่อความชื้น</h3>\n                        <p>ชิ้นส่วน MSD ที่หมดอายุหลังสัมผัสอากาศ ติดตามหรือทิ้ง การติดตามด้วยมือไม่ทันกับจังหวะการผลิต</p>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Solutions: DigiWin แก้ปัญหาอย่างไร (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Solutions: DigiWin แก้ปัญหาอย่างไร (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Solutions: DigiWin แก้ปัญหาอย่างไร (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="solutions-section">\n    <div class="dw-section-scene">\n                <svg aria-hidden="true" viewBox="0 0 1400 900" fill="none" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice">\n                    <line x1="200" y1="0" x2="200" y2="900" stroke="#000864" stroke-width="0.5" opacity="0.08"/>\n                    <line x1="400" y1="0" x2="400" y2="900" stroke="#000864" stroke-width="0.5" opacity="0.08"/>\n                    <line x1="600" y1="0" x2="600" y2="900" stroke="#000864" stroke-width="0.5" opacity="0.08"/>\n                    <line x1="800" y1="0" x2="800" y2="900" stroke="#000864" stroke-width="0.5" opacity="0.08"/>\n                    <line x1="1000" y1="0" x2="1000" y2="900" stroke="#000864" stroke-width="0.5" opacity="0.08"/>\n                    <line x1="1200" y1="0" x2="1200" y2="900" stroke="#000864" stroke-width="0.5" opacity="0.08"/>\n                    <path d="M200 300 L400 300 L400 500 L600 500" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n                    <path d="M800 200 L1000 200 L1000 400 L1200 400" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n                    <path d="M200 600 L400 600 L400 700 L800 700" stroke="#000864" stroke-width="1.5" opacity="0.1"/>\n                    <circle cx="200" cy="300" r="6" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.15"/>\n                    <circle cx="400" cy="300" r="4" fill="#000864" opacity="0.12"/>\n                    <circle cx="400" cy="500" r="4" fill="#000864" opacity="0.12"/>\n                    <circle cx="600" cy="500" r="6" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.15"/>\n                    <circle cx="800" cy="200" r="6" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.15"/>\n                    <circle cx="1000" cy="200" r="4" fill="#000864" opacity="0.12"/>\n                    <circle cx="1000" cy="400" r="4" fill="#000864" opacity="0.12"/>\n                    <circle cx="1200" cy="400" r="6" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.15"/>\n                    <rect x="550" y="250" width="60" height="40" rx="3" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.12"/>\n                    <rect x="900" y="550" width="60" height="40" rx="3" stroke="#000864" stroke-width="1.5" fill="none" opacity="0.12"/>\n                    <rect x="300" y="400" width="40" height="25" rx="2" stroke="#000864" stroke-width="1" fill="none" opacity="0.1"/>\n                    <rect x="1050" y="300" width="40" height="25" rx="2" stroke="#000864" stroke-width="1" fill="none" opacity="0.1"/>\n                    <circle cx="700" cy="350" r="3" fill="#00AFF0" opacity="0.12"/>\n                    <circle cx="1100" cy="650" r="4" fill="#000864" opacity="0.06"/>\n                </svg>\n            </div>\n            <div class="solutions-inner" style="position: relative; z-index: 2;">\n                <div class="solutions-header">\n                    <h2>DigiWin แก้ปัญหาอย่างไร</h2>\n                    <p>ความสามารถที่ออกแบบมาเฉพาะสำหรับการประกอบอิเล็กทรอนิกส์</p>\n                </div>\n                <div class="solutions-grid">\n                    <div class="solution-card">\n                        <div class="solution-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M10 13a5 5 0 0 0 7.54.54l3-3a5 5 0 0 0-7.07-7.07l-1.72 1.71"/><path d="M14 11a5 5 0 0 0-7.54-.54l-3 3a5 5 0 0 0 7.07 7.07l1.71-1.71"/></svg></div>\n                        <h3>เชื่อมต่อเครื่อง SMT</h3>\n                        <p>เชื่อมต่อโดยตรงกับเครื่อง Pick-and-Place ตรวจสอบรีลก่อนติดตั้ง ป้องกันข้อผิดพลาดจากชิ้นส่วนผิดตั้งแต่ต้นทาง</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>ตรวจสอบรีลที่ Feeder</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>ป้องกันชิ้นส่วนผิด</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>ดาวน์โหลดโปรแกรมอัตโนมัติ</span>\n                            </div>\n                        </div>\n                    </div>\n                    <div class="solution-card">\n                        <div class="solution-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M20.59 13.41l-7.17 7.17a2 2 0 0 1-2.83 0L2 12V2h10l8.59 8.59a2 2 0 0 1 0 2.82z"/><line x1="7" y1="7" x2="7.01" y2="7"/></svg></div>\n                        <h3>Traceability ระดับชิ้นส่วน</h3>\n                        <p>ติดตามทุกรีลไปยังทุกตำแหน่งบนบอร์ด รู้แน่ชัดว่าชิ้นส่วนไหนอยู่ในผลิตภัณฑ์ไหน</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>เชื่อมโยงรีลกับซีเรียลนัมเบอร์</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>ตรวจสอบย้อนกลับได้ครบทั้งสองทาง</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>ลดขอบเขตการ Recall</span>\n                            </div>\n                        </div>\n                    </div>\n                    <div class="solution-card">\n                        <div class="solution-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2.69l5.66 5.66a8 8 0 1 1-11.31 0z"/></svg></div>\n                        <h3>จัดการ MSD</h3>\n                        <p>ติดตาม Floor Life อัตโนมัติสำหรับชิ้นส่วนที่ไวต่อความชื้น ระบบแจ้งเตือนก่อนหมดอายุเพื่อลดของเสีย</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>นับถอยหลัง Floor Life อัตโนมัติ</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>ติดตามรอบ Bake-Out</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>แจ้งเตือนและบล็อกเมื่อหมดอายุ</span>\n                            </div>\n                        </div>\n                    </div>\n                    <div class="solution-card">\n                        <div class="solution-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="3"/><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/></svg></div>\n                        <h3>เชื่อมต่อ AOI/ICT</h3>\n                        <p>เชื่อมผลการตรวจสอบเข้ากับ MES ติดตามแนวโน้มข้อบกพร่องตามชิ้นส่วน เครื่องจักร พนักงาน และเวลา</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>จับข้อบกพร่องอัตโนมัติ</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>วิเคราะห์ Pareto</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>แนวโน้ม SPC</span>\n                            </div>\n                        </div>\n                    </div>\n                    <div class="solution-card" style="border: 2px solid rgba(0,175,240,0.3); background: linear-gradient(135deg, rgba(0,175,240,0.03), rgba(255,255,255,1));">\n                        <div class="solution-icon" style="background: linear-gradient(135deg, rgba(0,175,240,0.2), rgba(0,175,240,0.1));"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/><path d="M9 12l2 2 4-4"/></svg></div>\n                        <h3>BOI Compliance</h3>\n                        <p>กระทบยอดวัตถุดิบระดับใบสั่งผลิตสำหรับการตรวจสอบ BOI ติดตามการใช้ชิ้นส่วนจริงต่อใบสั่งประกอบ — สำคัญสำหรับชิ้นส่วนอิเล็กทรอนิกส์ที่อยู่ในบัญชี Bonded</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>รายงานพร้อมตรวจ BOI</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>ติดตามชิ้นส่วน Bonded</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>พิสูจน์แล้ว: ประหยัด 10M+ บาท/ปี</span>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Equipment: เชื่อมต่อเครื่องจักรโดยตรง (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Equipment: เชื่อมต่อเครื่องจักรโดยตรง (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Equipment: เชื่อมต่อเครื่องจักรโดยตรง (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="equipment-section">\n    <div class="equipment-inner" style="position: relative; z-index: 2;">\n                <h3>เชื่อมต่อเครื่องจักรโดยตรง</h3>\n                <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 16px; color: #666; max-width: 700px; margin: 0 auto 40px; line-height: 1.6;">DigiWin MES เชื่อมต่อโดยตรงกับสาย SMT, สถานีตรวจสอบ, เตา Reflow และอุปกรณ์ทดสอบ — เก็บข้อมูลการผลิตแบบเรียลไทม์โดยไม่ต้องป้อนข้อมูลเอง</p>\n    \n                <div style="margin-bottom: 32px;">\n                    <span style="font-family: \'JetBrains Mono\', monospace; font-size: 11px; font-weight: 500; text-transform: uppercase; letter-spacing: 0.1em; color: #00AFF0; display: block; margin-bottom: 12px;">SMT Pick-and-Place</span>\n                    <div class="equipment-logos">\n                        <div class="equipment-logo">Fuji</div>\n                        <div class="equipment-logo">Panasonic</div>\n                        <div class="equipment-logo">Yamaha</div>\n                        <div class="equipment-logo">Juki</div>\n                        <div class="equipment-logo">ASM</div>\n                    </div>\n                </div>\n    \n                <div style="margin-bottom: 32px;">\n                    <span style="font-family: \'JetBrains Mono\', monospace; font-size: 11px; font-weight: 500; text-transform: uppercase; letter-spacing: 0.1em; color: #00AFF0; display: block; margin-bottom: 12px;">AOI & Inspection</span>\n                    <div class="equipment-logos">\n                        <div class="equipment-logo">Koh Young</div>\n                        <div class="equipment-logo">Saki</div>\n                        <div class="equipment-logo">Omron</div>\n                    </div>\n                </div>\n    \n                <div>\n                    <span style="font-family: \'JetBrains Mono\', monospace; font-size: 11px; font-weight: 500; text-transform: uppercase; letter-spacing: 0.1em; color: #00AFF0; display: block; margin-bottom: 12px;">Reflow Ovens & Test</span>\n                    <div class="equipment-logos">\n                        <div class="equipment-logo">Heller</div>\n                        <div class="equipment-logo">BTU</div>\n                        <div class="equipment-logo">Keysight</div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Case Study: Hoo Chin Electronics (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Case Study: Hoo Chin Electronics (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Case Study: Hoo Chin Electronics (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="fade-in">\n    <div style="max-width: 800px; margin: 0 auto; padding: 0 24px;">\n                <div style="background: linear-gradient(135deg, rgba(0,175,240,0.04), rgba(0,8,100,0.04)); border: 1px solid rgba(0,175,240,0.2); border-left: 4px solid #00AFF0; border-radius: 12px; padding: 40px 40px 36px;">\n                    <span style="font-family: \'JetBrains Mono\', monospace; font-size: 11px; font-weight: 500; text-transform: uppercase; letter-spacing: 0.1em; color: #00AFF0; display: block; margin-bottom: 8px;">DigiWin ในอุตสาหกรรมอิเล็กทรอนิกส์ไทย</span>\n                    <h3 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 24px; font-weight: 700; color: #000864; margin: 0 0 16px;">Hoo Chin Electronics (Thailand)</h3>\n                    <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 16px; line-height: 1.7; color: #333; margin: 0 0 20px;">Hoo Chin Electronics ผู้ผลิตอิเล็กทรอนิกส์ไทยและหนึ่งในลูกค้าของ DigiWin ในประเทศไทย เลือก DigiWin ERP เพื่อจัดการความซับซ้อนของการผลิตแบบ High-Mix, BOI Compliance และการติดตามชิ้นส่วนหลายวัสดุ — ความท้าทายเดียวกับที่โรงงานของคุณเผชิญทุกวัน</p>\n                    <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 14px; line-height: 1.6; color: #666; margin: 0;">นี่ไม่ใช่แค่ตัวอย่างจากเอเชีย Hoo Chin ดำเนินงานในประเทศไทย ปฏิบัติตามกฎระเบียบไทย และทำงานกับซัพพลายเชนไทย — หลักฐานว่า DigiWin ส่งมอบผลลัพธ์ในตลาดของคุณ</p>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products: แนะนำสำหรับอิเล็กทรอนิกส์ (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products: แนะนำสำหรับอิเล็กทรอนิกส์ (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products: แนะนำสำหรับอิเล็กทรอนิกส์ (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="products-section">\n    <div class="products-inner">\n                <div class="products-header">\n                    <h2>ผลิตภัณฑ์แนะนำสำหรับอิเล็กทรอนิกส์</h2>\n                </div>\n                <div class="products-grid">\n                    <a href="../products/mes.html" class="product-card">\n                        <div class="product-card-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><rect x="2" y="7" width="20" height="14" rx="2"/><path d="M6 7V5a2 2 0 0 1 2-2h8a2 2 0 0 1 2 2v2"/><circle cx="6" cy="12" r="1"/><circle cx="10" cy="12" r="1"/><circle cx="14" cy="12" r="1"/><circle cx="18" cy="12" r="1"/></svg></div>\n                        <h3>MES</h3>\n                        <p>Traceability ระดับชิ้นส่วน, เชื่อมต่อ SMT, จัดการ MSD และติดตามคุณภาพแบบเรียลไทม์สำหรับอิเล็กทรอนิกส์</p>\n                        <span class="product-card-link">เรียนรู้เพิ่มเติม <span>→</span></span>\n                    </a>\n                    <a href="../products/wms.html" class="product-card">\n                        <div class="product-card-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"/><polyline points="3.29 7 12 12 20.71 7"/><line x1="12" y1="22" x2="12" y2="12"/></svg></div>\n                        <h3>sFLS WMS</h3>\n                        <p>จัดการรีล, ดูแลชิ้นส่วนไวต่อความชื้น และ Kitting Support สำหรับคลังสินค้าอิเล็กทรอนิกส์</p>\n                        <span class="product-card-link">เรียนรู้เพิ่มเติม <span>→</span></span>\n                    </a>\n                    <a href="../products/aiot.html" class="product-card">\n                        <div class="product-card-icon"><svg aria-hidden="true" viewBox="0 0 24 24"><path d="M12 2v4m0 12v4M4.93 4.93l2.83 2.83m8.48 8.48l2.83 2.83M2 12h4m12 0h4M4.93 19.07l2.83-2.83m8.48-8.48l2.83-2.83"/><circle cx="12" cy="12" r="3"/></svg></div>\n                        <h3>AIoT</h3>\n                        <p>เชื่อมต่อเครื่องจักรสำหรับสาย SMT, เตา Reflow และอุปกรณ์ทดสอบ OEE แบบเรียลไทม์และติดตามกระบวนการ</p>\n                        <span class="product-card-link">เรียนรู้เพิ่มเติม <span>→</span></span>\n                    </a>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ: อิเล็กทรอนิกส์ (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ: อิเล็กทรอนิกส์ (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"FAQ: อิเล็กทรอนิกส์ (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="elec-faq">\n    <div style="max-width: 800px; margin: 0 auto; padding: 0 24px;">\n            <h2 style="font-family: \'Noto Sans\', sans-serif; font-size: 28px; font-weight: 700; color: #000864; margin-bottom: 32px; text-align: center;">Frequently Asked Questions</h2>\n            <div style="display: flex; flex-direction: column; gap: 12px;">\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">ระบบ MES ไหนเหมาะสำหรับการประกอบอิเล็กทรอนิกส์ในประเทศไทย?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">DigiWin MES ออกแบบมาเฉพาะสำหรับความซับซ้อนของการประกอบอิเล็กทรอนิกส์ ด้วยการเชื่อมต่อเครื่อง SMT โดยตรงที่ MES ทั่วไปไม่สามารถเทียบได้ ระบบรองรับการผลิตแบบ High-Mix, Low-Volume ด้วยชิ้นส่วนนับพันประเภท ติดตามทุกรีลไปยังทุกตำแหน่งบนบอร์ด ถูกใช้งานทั่วระบบนิเวศอิเล็กทรอนิกส์ไทยที่ส่งออกมูลค่ากว่า 40,000 ล้านดอลลาร์สหรัฐต่อปี ตั้งแต่ฮาร์ดดิสก์ไดรฟ์ไปจนถึงอิเล็กทรอนิกส์ยานยนต์</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">DigiWin MES เชื่อมต่อกับเครื่อง SMT ของ Fuji และ Panasonic ได้หรือไม่?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">ได้ DigiWin เชื่อมต่อโดยตรงกับเครื่อง SMT ชั้นนำทุกแบรนด์ ได้แก่ Fuji, Panasonic, Yamaha, Juki และ ASM Pick-and-Place รวมถึงระบบตรวจสอบ AOI และ ICT จาก Koh Young, Omron และ Keysight การเชื่อมต่อนี้ช่วยให้ตรวจสอบรีลที่ Feeder ป้องกันชิ้นส่วนผิด และดาวน์โหลดโปรแกรมอัตโนมัติ ขจัดการป้อนข้อมูลด้วยมือที่เป็นสาเหตุของการวางชิ้นส่วนผิด</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">DigiWin จัดการกับการติดตามชิ้นส่วนไวต่อความชื้น (MSD) อย่างไร?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">DigiWin จัดการ Floor Life อัตโนมัติทั้งกระบวนการ ระบบเริ่มนับถอยหลังอัตโนมัติทันทีที่เปิดซองบรรจุ MSD ติดตามรอบ Bake-Out สำหรับชิ้นส่วนที่ต้อง Recondition และส่งแจ้งเตือนหมดอายุพร้อมบล็อกไม่ให้ใช้ชิ้นส่วนหมดอายุบนสายการผลิต วิธีอัตโนมัตินี้ช่วยลดของเสียจาก MSD ได้ 45% เทียบกับการติดตามด้วยมือ</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">DigiWin รองรับ BOI Compliance สำหรับโรงงานอิเล็กทรอนิกส์หรือไม่?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">ได้ DigiWin กระทบยอดวัตถุดิบระดับใบสั่งผลิตที่ออกแบบมาเฉพาะสำหรับการตรวจสอบ BOI ในอุตสาหกรรมอิเล็กทรอนิกส์ ระบบติดตามการใช้ชิ้นส่วนจริงต่อใบสั่งประกอบ ซึ่งสำคัญสำหรับชิ้นส่วนอิเล็กทรอนิกส์ในบัญชี Bonded ที่ต้องกระทบยอดอากรนำเข้าอย่างแม่นยำ โรงงานอิเล็กทรอนิกส์ที่ใช้ DigiWin สำหรับ BOI Compliance รายงานว่าประหยัดได้กว่า 10 ล้านบาทต่อปีจากการเบิกคืนอากรที่แม่นยำและรายงานพร้อมตรวจ BOI</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">DigiWin WMS ให้ความแม่นยำในการหยิบได้เท่าไหร่?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">DigiWin sFLS WMS ให้ความแม่นยำในการหยิบ 99.9% สำหรับคลังสินค้าอิเล็กทรอนิกส์ ระบบจัดการสินค้าคงคลังระดับรีลพร้อมดูแลชิ้นส่วน MSD อย่างแม่นยำ Kitting Support สำหรับใบสั่งผลิต และตรวจสอบด้วย Barcode ทุกขั้นตอน สำหรับโรงงานอิเล็กทรอนิกส์ที่จัดการชิ้นส่วนหลายร้อยรายการต่อผลิตภัณฑ์และรีลนับพันในคลัง ความแม่นยำระดับนี้ป้องกันข้อผิดพลาดที่มีราคาแพง เพราะวางชิ้นส่วนผิดเพียงตัวเดียวอาจทำให้ต้องทิ้งทั้งล็อต</p>\n                </div>\n              </details>\n            </div>\n          </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: จัดการความซับซ้อนของอิเล็กทรอนิกส์ (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: จัดการความซับซ้อนของอิเล็กทรอนิกส์ (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: จัดการความซับซ้อนของอิเล็กทรอนิกส์ (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="elec-cta-section">\n    <div class="elec-cta-super-d" aria-hidden="true"></div>\n    <div class="elec-cta-wave-flow" aria-hidden="true"></div>\n    <div class="elec-cta-container">\n      <h2 class="elec-cta-title">จัดการความซับซ้อนของอิเล็กทรอนิกส์</h2>\n      <p class="elec-cta-subtitle">ดูว่า DigiWin รองรับการผลิตแบบ High-Mix อย่างไร</p>\n      <div class="elec-cta-btn-row">\n        <a href="/th/demo/" class="elec-cta-btn elec-cta-btn--primary">ติดต่อเรา</a>\n        <a href="/industries.html" class="elec-cta-btn elec-cta-btn--ghost">ดูอุตสาหกรรมอื่นๆ</a>\n      </div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Column"}}},"decoration":{}}} -->\n<!-- wp:html --><style>\n.elec-related-grid{display:grid!important;grid-template-columns:repeat(auto-fit,minmax(280px,1fr))!important;gap:24px!important;max-width:1200px!important;margin:0 auto!important}\n.elec-related-card{display:block!important;padding:24px!important;background:#fff!important;border-radius:12px!important;text-decoration:none!important;border:1px solid #e5e7eb!important;color:#333!important;line-height:1.6!important}\n.elec-related-card-title{font-size:18px!important;font-weight:600!important;color:#000864!important;margin:0 0 8px 0!important}\n.elec-related-card-desc{font-size:14px!important;color:#666!important;margin:0!important}\n</style><div class="elec-related-section">\n    <h2 class="elec-related-heading">Explore Related Solutions</h2>\n    <div class="elec-related-grid">\n      <a href="/industries/automotive/" class="elec-related-card">\n        <h3 class="elec-related-card-title">Automotive</h3>\n        <p class="elec-related-card-desc">ระบบ ERP และ MES ที่ออกแบบเฉพาะสำหรับผู้ผลิตชิ้นส่วนยานยนต์และ OEM Supplier</p>\n      </a>\n      <a href="/industries/metal-plastics/" class="elec-related-card">\n        <h3 class="elec-related-card-title">Metal &amp; Plastics</h3>\n        <p class="elec-related-card-desc">โซลูชันครบวงจรสำหรับ Die Casting, ฉีดพลาสติก และโรงงานขึ้นรูปโลหะ</p>\n      </a>\n      <a href="/products/erp/" class="elec-related-card">\n        <h3 class="elec-related-card-title">ERP</h3>\n        <p class="elec-related-card-desc">ระบบ ERP สำหรับโรงงานผลิตครบวงจร — ตั้งแต่ BOM ถึงบัญชีการเงินถึง BOI</p>\n      </a>\n      <a href="/products/mes/" class="elec-related-card">\n        <h3 class="elec-related-card-title">MES</h3>\n        <p class="elec-related-card-desc">ระบบบริหารการผลิตแบบเรียลไทม์ — ติดตาม OEE, SPC และใบสั่งผลิตแบบไร้กระดาษ</p>\n      </a>\n      <a href="/products/wms/" class="elec-related-card">\n        <h3 class="elec-related-card-title">WMS</h3>\n        <p class="elec-related-card-desc">ระบบบริหารคลังสินค้าอัจฉริยะ Barcode/RFID — ตั้งแต่รับเข้าถึงจัดส่ง พร้อม Traceability เต็มรูปแบบ</p>\n      </a>\n      <a href="/products/aiot/" class="elec-related-card">\n        <h3 class="elec-related-card-title">AIoT</h3>\n        <p class="elec-related-card-desc">เชื่อมต่อเครื่องจักรเข้ากับ ERP ด้วยเซ็นเซอร์ IoT, Edge Computing และ AI Analytics</p>\n      </a>\n    </div>\n  </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100783;

