DELETE FROM wp_postmeta WHERE post_id = 100783 AND meta_key = '_et_pb_custom_css';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100783, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === ELEC HERO (S1) === */\n/* TODO: Review and remap class selectors to use eleh prefix */\n/* TODO: Add section container: .eleh-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n\n\n/* TODO: PSEUDO-ELEMENTS using global classes (port manually) */\n.auto-hero::before, .elec-hero::before, .metal-hero::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%233798E4\' fill-opacity=\'0.06\'%3E%3Cpath d=\'M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");opacity:0.5}\n.auto-hero, .elec-hero, .metal-hero{background:linear-gradient(135deg, #000432 0%, #000864 50%, #001080 100%);padding:140px 0 100px;position:relative;overflow:hidden}\n.auto-hero-inner, .elec-hero-inner, .metal-hero-inner{max-width:1200px;margin:0 auto;padding:0 24px;position:relative;z-index:1;text-align:center}\n.auto-hero-badge, .elec-hero-badge, .metal-hero-badge{display:inline-flex;align-items:center;gap:8px;background:rgba(0, 175, 240, 0.2);border:1px solid rgba(0, 175, 240, 0.3);padding:8px 20px;border-radius:50px;color:#7EC8F2;font-size:14px;font-weight:500;margin-bottom:24px}\n.auto-hero h1, .elec-hero h1, .metal-hero h1{font-family:\'Noto Sans\', sans-serif;font-size:52px;font-weight:700;color:#fff;margin-bottom:20px;line-height:1.15}\n.auto-hero h1 span, .elec-hero h1 span, .metal-hero h1 span{color:#00AFF0}\n.elec-hero-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:20px;color:rgba(255,255,255,0.85);max-width:700px;margin:0 auto 50px;line-height:1.6}\n.elec-hero-stats{display:flex;justify-content:center;gap:60px}\n.elec-hero-stat{text-align:center}\n.elec-hero-stat-value{font-family:\'Noto Sans\',sans-serif;font-size:42px;font-weight:700;color:#00AFF0}\n.elec-hero-stat-label{font-size:14px;color:rgba(255,255,255,0.85);margin-top:4px}\n@media (max-width:1024px){.auto-hero h1, .elec-hero h1, .metal-hero h1{font-size:40px}.auto-hero-stats, .elec-hero-stats, .metal-hero-stats{gap:40px}.stakes-grid, .challenges-grid{grid-template-columns:1fr}.solutions-grid{grid-template-columns:1fr}.products-grid{grid-template-columns:1fr}}\n@media (max-width:640px){.auto-hero, .elec-hero, .metal-hero{padding:120px 0 80px}.auto-hero h1, .elec-hero h1, .metal-hero h1{font-size:32px}.auto-hero-subtitle, .elec-hero-subtitle, .metal-hero-subtitle{font-size:17px}.auto-hero-stats, .elec-hero-stats, .metal-hero-stats{flex-direction:column;gap:24px}.auto-hero-stat-value, .elec-hero-stat-value, .metal-hero-stat-value{font-size:36px}.stake-card, .challenge-card{padding:32px 24px}.solution-card{padding:32px}.cta-section h2{font-size:28px}.cta-buttons{flex-direction:column}}\n/* @media (prefers-reduced-motion:reduce){.products-hero-content,.hero-stack-visual,.products-hero::before,.products-hero-badge::before,.stack-layer,.stack-layer::before,.data-particle,.ecosystem-node,.ecosystem-line,.ecosystem-ring,.data-flow-line,.data-flow-dot,.integration-hub::before,.integration-hub::after,.pp-card,.why-card,.why-card-icon,.pp-card-icon,.products-cta-glow,.dw-d-parallax,.dw-wave-flow,.dw-d-bg{animation:none !important;transition:none !important}.pp-card.visible{opacity:1;transform:none}} */\n\n@media(prefers-reduced-motion:reduce){}\n\n/* Super D decoration */\n.dw-d-bg{position:absolute;top:-20%;right:-10%;bottom:auto;left:auto;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center top;background-size:contain;opacity:0.12;pointer-events:none;z-index:0}\n\n/* Divi overrides */\n.et_pb_section .elec-hero h1{font-weight:700 !important;line-height:1.15 !important}\n.et_pb_section .elec-hero-subtitle{line-height:32px !important;-webkit-font-smoothing:auto !important;padding-bottom:0 !important}\n\n.et_pb_section .elec-hero-stat-value {\n            line-height: 67.2px !important;\n        \n            color: rgb(0, 175, 240) !important;\n\n            -webkit-font-smoothing: auto !important;\n}\n\n.et_pb_section .elec-hero-stat-label {\n            line-height: 22.4px !important;\n        \n            margin-top: 4px !important;\n\n            -webkit-font-smoothing: auto !important;\n}\n/* === CONTEXT (S2) === */\n/* TODO: Review and remap class selectors to use con prefix */\n/* TODO: Add section container: .context-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n\n\n.fade-in{opacity:1;transform:none}\n.fade-in.visible{opacity:1;transform:translateY(0)}\n.fade-in.no-delay{opacity:1;transform:none;transition:none}\n@media (prefers-reduced-motion:reduce){.fade-in{opacity:1;transform:none;transition:none}}\n.context-section{padding:100px 0;background:#fff}\n.context-inner{max-width:900px;margin:0 auto;padding:0 24px;text-align:center}\n.context-inner h2{font-family:\'Noto Sans\', sans-serif;font-size:36px;color:#000864;margin-bottom:24px}\n.context-inner p{font-size:18px;color:#5b6b80;line-height:1.8}\n.context-inner p strong{color:#000864}\n/* Divi overrides */\n.et_pb_section .context-inner h2{font-weight:700 !important;line-height:1.6 !important}\n.et_pb_section .context-inner p{padding-bottom:0 !important;line-height:1.8 !important}\n\n@media(prefers-reduced-motion:reduce){}\n/* === CHALLENGES (S3) === */\n/* TODO: Review and remap class selectors to use cha prefix */\n/* TODO: Add section container: .challenges-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n\n\n/* TODO: HOVER STATES using global classes (port manually) */\n/* .stake-card:hover .stake-icon, .challenge-card:hover .challenge-icon{background:linear-gradient(135deg, #00AFF0, #003CC8)} */\n/* .stake-card:hover .stake-icon svg, .challenge-card:hover .challenge-icon svg{stroke:#fff} */\n.fade-in{opacity:1;transform:none}\n.fade-in.visible{opacity:1;transform:translateY(0)}\n.fade-in.no-delay{opacity:1;transform:none;transition:none}\n@media (prefers-reduced-motion:reduce){.fade-in{opacity:1;transform:none;transition:none}}\n.stakes-section, .challenges-section{padding:100px 0;background:#F5F7FA}\n.stakes-inner, .challenges-inner{max-width:1100px;margin:0 auto;padding:0 24px}\n.stakes-header, .challenges-header{text-align:center;margin-bottom:60px}\n.stakes-header h2, .challenges-header h2{font-family:\'Noto Sans\', sans-serif;font-size:36px;color:#000864;margin-bottom:16px}\n.stakes-header p, .challenges-header p{font-size:18px;color:#5b6b80}\n.challenges-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:32px}\n.challenge-card{background:linear-gradient(145deg,#fef2f2 0%,#fee2e2 100%);border:1px solid #fecaca;border-radius:20px;padding:40px 32px;text-align:center}\n.challenge-icon{width:72px;height:72px;background:linear-gradient(135deg,#fee2e2,#fecaca);border-radius:50%;display:flex;align-items:center;justify-content:center;margin:0 auto 24px;transition:all 0.4s ease}\n.challenge-icon svg{width:32px;height:32px;stroke:#b91c1c;stroke-width:1.5;fill:none}\n.challenge-card h3{font-family:\'Noto Sans\',sans-serif;font-size:22px;color:#991b1b;margin-bottom:16px}\n.challenge-card p{font-size:15px;color:#b91c1c;line-height:1.7}\n.challenge-card:hover .challenge-icon{background:linear-gradient(135deg,#00AFF0,#003CC8)}\n.challenge-card:hover .challenge-icon svg{stroke:#fff}\n/* Divi overrides */\n.et_pb_section .challenges-header h2{font-weight:700 !important;line-height:1.6 !important}\n.et_pb_section .challenge-card h3{line-height:35.2px !important}\n.et_pb_section .challenge-card p{line-height:25.5px !important;padding-bottom:0 !important}\n@media(max-width:1024px){.challenges-grid{grid-template-columns:1fr}}\n@media(max-width:640px){.challenge-card{padding:32px 24px}}\n\n/* Defensive SVG sizing */\nsvg:not([width]):not([class]){max-width:48px;max-height:48px}\n@media(prefers-reduced-motion:reduce){}\n/* === SOLUTIONS (S4) === */\n.solutions-section{padding:100px 0;background:#fff;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.dw-section-scene{position:absolute;inset:0;pointer-events:none;z-index:0}\n.dw-section-scene svg{width:100%;height:100%;position:absolute;top:0;left:0}\n.solutions-inner{max-width:1100px;margin:0 auto;padding:0 24px}\n.solutions-header{text-align:center;margin-bottom:60px}\n.solutions-header h2{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:700;color:#000864;line-height:1.6;margin:0 0 16px;padding:0}\n.solutions-header p{font-family:\'Noto Sans\',sans-serif;font-size:18px;color:#5b6b80;line-height:1.6;margin:0;padding:0}\n.solutions-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:32px}\n.solution-card{background:#fff;border:1px solid #e2e8f0;border-radius:20px;padding:40px;transition:all 0.3s ease}\n.solution-card:hover{border-color:#00AFF0;box-shadow:0 12px 40px rgba(0,175,240,0.12)}\n.solution-icon{width:64px;height:64px;background:linear-gradient(135deg,rgba(0,175,240,0.15),rgba(0,175,240,0.05));border-radius:16px;display:flex;align-items:center;justify-content:center;margin-bottom:24px;transition:all 0.4s ease}\n.solution-icon svg{width:28px;height:28px;stroke:#00AFF0;stroke-width:1.5;fill:none}\n.solution-card:hover .solution-icon{background:linear-gradient(135deg,#00AFF0,#003CC8)}\n.solution-card:hover .solution-icon svg{stroke:#fff}\n.solution-card h3{font-family:\'Noto Sans\',sans-serif;font-size:22px;font-weight:700;color:#000864;line-height:1.6;margin:0 0 12px;padding:0}\n.solution-card>p{font-family:\'Noto Sans\',sans-serif;font-size:15px;color:#5b6b80;line-height:1.7;margin:0 0 20px;padding:0}\n.solution-features{display:flex;flex-direction:column;gap:10px}\n.solution-feature{display:flex;align-items:center;gap:10px;font-size:14px;color:#475569}\n.solution-feature svg{width:18px;height:18px;color:#00AFF0;flex-shrink:0}\n@media(max-width:1024px){\n  .solutions-grid{grid-template-columns:1fr}\n}\n@media(max-width:768px){\n  .solutions-section{padding:80px 0}\n  .solution-card{padding:32px}\n}\n@media(prefers-reduced-motion:reduce){.solution-card{transition:none !important}.solution-icon{transition:none !important}}\n/* Divi line-height overrides */\n.et_pb_section .solutions-header h2{line-height:57.6px !important}\n.et_pb_section .solutions-header p{line-height:28.8px !important}\n.et_pb_section .solution-card h3{line-height:35.2px !important}\n.et_pb_section .solution-card>p{line-height:25.5px !important}\n.et_pb_section .solution-feature span{line-height:22.4px !important}\n/* === EQUIPMENT (S5) === */\n/* TODO: Review and remap class selectors to use equ prefix */\n/* TODO: Add section container: .equipment-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n\n\n.fade-in{opacity:1;transform:none}\n.fade-in.visible{opacity:1;transform:translateY(0)}\n.fade-in.no-delay{opacity:1;transform:none;transition:none}\n@media (prefers-reduced-motion:reduce){.fade-in{opacity:1;transform:none;transition:none}}\n.oem-section, .equipment-section, .processes-section{padding:80px 0;background:#F5F7FA}\n.oem-inner, .equipment-inner, .processes-inner{max-width:1000px;margin:0 auto;padding:0 24px;text-align:center}\n.oem-inner h3, .equipment-inner h3, .processes-inner h3{font-family:\'Noto Sans\', sans-serif;font-size:24px;color:#000864;margin-bottom:40px}\n.oem-logos, .equipment-logos, .processes-logos{display:flex;flex-wrap:wrap;justify-content:center;gap:24px}\n.oem-logo, .equipment-logo, .process-logo{background:#fff;border:1px solid #e2e8f0;border-radius:12px;padding:20px 32px;font-family:\'Noto Sans\', sans-serif;font-size:16px;font-weight:600;color:#475569}\n\n@media(prefers-reduced-motion:reduce){}\n\n.et_pb_section .equipment-logo {\n            line-height: 25.6px !important;\n        \n            -webkit-font-smoothing: auto !important;\n}\n/* === FADE IN / CASE STUDY CALLOUT (S6) === */\n.fade-in{opacity:1;transform:none;padding:80px 0;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n/* Divi overrides for inline-styled elements */\n.et_pb_section .fade-in h3{line-height:38.4px !important;margin-bottom:16px !important}\n.et_pb_section .fade-in p{padding-bottom:0 !important}\n.et_pb_section .fade-in p:first-of-type{line-height:27.2px !important}\n.et_pb_section .fade-in p:last-of-type{line-height:22.4px !important}\n@media(prefers-reduced-motion:reduce){}\n/* === PRODUCTS (S7) === */\n/* TODO: Review and remap class selectors to use pro prefix */\n/* TODO: Add section container: .products-section{...;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px} */\n\n\n/* === PSEUDO-ELEMENTS (auto-ported from styles.css) === */\n.pro-grid-section::before{content:\'\';position:absolute;top:0;left:0;right:0;height:1px;background:linear-gradient(90deg, transparent, #00AFF0, transparent)}\n.products-section-label::before,.products-section-label::after{content:\'\';width:40px;height:1px;background:linear-gradient(90deg, transparent, #00AFF0)}\n.products-section-label::after{background:linear-gradient(90deg, #00AFF0, transparent)}\n/* TODO: HOVER STATES using global classes (port manually) */\n/* .product-card:hover{border-color:#00AFF0;transform:translateY(-4px);box-shadow:0 12px 40px rgba(0, 175, 240, 0.12)} */\n/* .product-card:hover .product-card-icon{background:linear-gradient(135deg, #00AFF0, #003CC8)} */\n/* .product-card:hover .product-card-icon svg{stroke:#fff} */\n/* .product-card:hover .product-card-link{gap:10px} */\n.fade-in{opacity:1;transform:none}\n.fade-in.visible{opacity:1;transform:translateY(0)}\n.fade-in.no-delay{opacity:1;transform:none;transition:none}\n@media (prefers-reduced-motion:reduce){.fade-in{opacity:1;transform:none;transition:none}}\n.products-section{padding:100px 0;background:#fff}\n.products-inner{max-width:1100px;margin:0 auto;padding:0 24px}\n.products-header{text-align:center;margin-bottom:60px}\n.products-header h2{font-family:\'Noto Sans\', sans-serif;font-size:36px;color:#000864;margin-bottom:16px}\n.products-grid{display:grid;grid-template-columns:repeat(3, 1fr);gap:24px}\n.product-card{background:#fff;border:2px solid #e2e8f0;border-radius:16px;padding:32px;text-decoration:none;transition:all 0.3s ease;display:block}\n.product-card-icon{width:56px;height:56px;background:linear-gradient(135deg,rgba(0,175,240,0.1),rgba(0,175,240,0.05));border-radius:14px;display:flex;align-items:center;justify-content:center;margin-bottom:20px;transition:all 0.4s ease}\n.product-card-icon svg{width:28px;height:28px;stroke:#00AFF0;stroke-width:1.5;fill:none}\n.product-card h3{font-family:\'Noto Sans\',sans-serif;font-size:20px;color:#000864;margin-bottom:12px}\n.product-card p{font-size:14px;color:#5b6b80;line-height:1.6;margin-bottom:16px}\n.product-card-link{display:inline-flex;align-items:center;gap:6px;color:rgb(3, 105, 161) !important;font-family:\'Noto Sans\',sans-serif;font-weight:600;font-size:14px}\n.product-card:hover{border-color:#00AFF0;transform:translateY(-4px);box-shadow:0 12px 40px rgba(0,175,240,0.12)}\n.product-card:hover .product-card-icon{background:linear-gradient(135deg,#00AFF0,#003CC8)}\n.product-card:hover .product-card-icon svg{stroke:#fff}\n.product-card:hover .product-card-link{gap:10px}\n/* Divi overrides */\n.et_pb_section .products-header h2{font-weight:700 !important;line-height:1.6 !important}\n.et_pb_section .product-card h3{line-height:32px !important}\n.et_pb_section .product-card p{padding-bottom:0 !important}\n@media (max-width:1024px){.auto-hero h1, .elec-hero h1, .metal-hero h1{font-size:40px}.auto-hero-stats, .elec-hero-stats, .metal-hero-stats{gap:40px}.stakes-grid, .challenges-grid{grid-template-columns:1fr}.solutions-grid{grid-template-columns:1fr}.products-grid{grid-template-columns:1fr}}\n/* .products-grid-section{padding:120px 0;background:linear-gradient(180deg, #f8fafc 0%, #ffffff 30%, #ffffff 70%, #f8fafc 100%);position:relative;overflow:hidden} */\n/* .products-grid-section .grid-pattern{position:absolute;top:0;left:0;right:0;bottom:0;background-image:radial-gradient(circle, rgba(0, 175, 240, 0.03) 1px, transparent 1px);background-size:30px 30px;pointer-events:none} */\n/* .products-section-header{max-width:700px;margin:0 auto 80px;text-align:center;position:relative;z-index:1} */\n/* .products-section-label{font-family:\'JetBrains Mono\', monospace;font-size:11px;font-weight:500;color:#00AFF0;text-transform:uppercase;letter-spacing:0.15em;margin-bottom:16px;display:flex;align-items:center;justify-content:center;gap:12px} */\n/* .products-section-title{font-family:\'Noto Sans\', sans-serif;font-size:44px;font-weight:700;color:#000864;margin:0 0 16px 0;letter-spacing:-0.02em} */\n/* .products-section-subtitle{font-family:\'Noto Sans\', sans-serif;font-size:18px;color:#5b6b80;line-height:1.6} */\n/* @media (max-width:640px){.products-hero{padding:120px 0 60px;min-height:auto}.products-hero h1{font-size:28px}.products-hero-stats{flex-direction:column;gap:20px;align-items:center}.products-hero-stat{text-align:center}.products-section-title,